@startuml
skinparam classAttributeIconSize 0
skinparam class {
  BackgroundColor #F5F5F5
  BorderColor Black
  FontName Arial
  FontSize 14
}
skinparam stereotypeCBackgroundColor #B8E0B8
skinparam stereotypeCBorderColor Black

class "Proyecto" as Proyecto {
  Nombre: "1 Texto"
  Fecha de inicio: 1 Tiempo
  Fecha de fin: 0..1 Tiempo
}

class "Miembros del Equipo" as MiembrosDelEquipo {
  Nombre: 1 Texto
  Apellidos: 1 Texto
  Rol: 0..* Texto
}

class "Lugar de Actuacion" as LugarDeActuacion {
  Nombre: 0..* Texto
  Coordenada X: 1 Número
  Coordenada Y: 1 Número
}

Proyecto <|-- MiembrosDelEquipo
Proyecto <|-- LugarDeActuacion

@enduml
